import{_ as l,o as e,c as i,a2 as t}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"2003年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2003年/核心总结.md","filePath":"01_letters/2003年/核心总结.md"}'),r={name:"01_letters/2003年/核心总结.md"};function o(h,a,n,u,s,d){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="_2003年巴菲特致股东信核心总结" tabindex="-1">2003年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2003年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2003年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增加136亿美元，每股账面价值增长21%</li><li>过去39年每股账面价值从19美元增至50,498美元，年复合增长率22.2%</li><li>相对标普500：落后7.7个百分点（标普涨28.7%）</li></ul><h2 id="主要投资决策" tabindex="-1">主要投资决策 <a class="header-anchor" href="#主要投资决策" aria-label="Permalink to &quot;主要投资决策&quot;">​</a></h2><h3 id="收购交易" tabindex="-1">收购交易 <a class="header-anchor" href="#收购交易" aria-label="Permalink to &quot;收购交易&quot;">​</a></h3><ol><li><p><strong>克莱顿家园(Clayton Homes)</strong>：17亿美元收购，预制住房行业标杆企业</p><ul><li>通过田纳西大学金融学生赠书触发，体现巴菲特独特的收购风格</li><li>行业整体困境中，克莱顿管理更优、融资更稳健</li></ul></li><li><p><strong>McLane公司</strong>：从沃尔玛收购，销售额约230亿美元的分销企业</p><ul><li>仅用两小时谈判，29天完成交割</li><li>无尽职调查，体现对沃尔玛诚信的信任</li></ul></li></ol><h3 id="投资组合调整" tabindex="-1">投资组合调整 <a class="header-anchor" href="#投资组合调整" aria-label="Permalink to &quot;投资组合调整&quot;">​</a></h3><ul><li>减持垃圾债券（2002年买入约80亿美元）</li><li>开始进入外汇市场，看空美元</li><li>持有大量现金，寻找低估资产</li></ul><h2 id="关键理念" tabindex="-1">关键理念 <a class="header-anchor" href="#关键理念" aria-label="Permalink to &quot;关键理念&quot;">​</a></h2><h3 id="保险浮存金" tabindex="-1">保险浮存金 <a class="header-anchor" href="#保险浮存金" aria-label="Permalink to &quot;保险浮存金&quot;">​</a></h3><ul><li>年末浮存金442亿美元，成本接近零</li><li>37年中有18年实现承保盈利</li><li>浮存金是伯克希尔增长的引擎</li></ul><h3 id="公司治理" tabindex="-1">公司治理 <a class="header-anchor" href="#公司治理" aria-label="Permalink to &quot;公司治理&quot;">​</a></h3><ul><li>批评CEO薪酬失控，特别是期权不计费用的会计处理</li><li>强调&quot;真正的独立性&quot;——董事利益与股东一致</li><li>伯克希尔董事每人持股超400万美元，无期权赠予</li></ul><h3 id="税收贡献" tabindex="-1">税收贡献 <a class="header-anchor" href="#税收贡献" aria-label="Permalink to &quot;税收贡献&quot;">​</a></h3><ul><li>伯克希尔2003年缴纳33亿美元联邦所得税</li><li>占美国企业所得税总额2.5%，市值仅占1%</li></ul><h2 id="行业洞察" tabindex="-1">行业洞察 <a class="header-anchor" href="#行业洞察" aria-label="Permalink to &quot;行业洞察&quot;">​</a></h2><h3 id="预制住房行业" tabindex="-1">预制住房行业 <a class="header-anchor" href="#预制住房行业" aria-label="Permalink to &quot;预制住房行业&quot;">​</a></h3><ul><li>行业因不负责任的贷款和证券化陷入危机</li><li>克莱顿模式更健康：要求合理首付、可持续贷款条款</li></ul><h3 id="保险业" tabindex="-1">保险业 <a class="header-anchor" href="#保险业" aria-label="Permalink to &quot;保险业&quot;">​</a></h3><ul><li>General Re已完成整改，恢复承保纪律</li><li>Ajit Jain的再保险业务独特，承担巨大非常规风险</li></ul><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;我们的股东可以以极低成本通过指数基金购买标普500指数。除非我们未来每股内在价值的增长超过标普的表现，否则查理和我在你们自己能做到的基础上不会增加任何价值。&quot;</p></blockquote><blockquote><p>&quot;我们会继续采用过去使用的资本配置做法。如果股票变得比整个企业明显便宜，我们将积极购买。&quot;</p></blockquote><hr><p><em>生成日期：2026年4月</em></p>',25)])])}const b=l(r,[["render",o]]);export{q as __pageData,b as default};
